int Independent_Set(MGraph G, int S[]) {
    int visited[MaxVertexNum] = {0};
    int count = 0;
    for (int i = 0; i < G->Nv; i++) {
        if (!visited[i]) {
            S[count++] = i + 1;
            visited[i] = 1;
            for (int j = 0; j < G->Nv; j++) {
                if (G->G[i][j] == 1) {
